// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

import "@openzeppelin/contracts/token/ERC721/extensions/ERC721URIStorage.sol";
import "@openzeppelin/contracts/utils/ReentrancyGuard.sol";
import "@openzeppelin/contracts/utils/Pausable.sol";
import "@openzeppelin/contracts/access/AccessControl.sol";

/**
 * @title Patient
 * @dev Contract for managing patient data, medical records, and emergency access.
 * @notice Extends ERC721 for medical record NFTs. Patients control their data and can grant/revoke access.
 */
contract Patient is ERC721URIStorage, ReentrancyGuard, Pausable, AccessControl {
    bytes32 public constant ADMIN_ROLE = keccak256("ADMIN_ROLE");
    bytes32 public constant INSURANCE_ROLE = keccak256("INSURANCE_ROLE");

    /// @dev Counter for generating unique NFT token IDs
    uint256 private _nextTokenId;

    /// @notice Mapping from wallet address to patient ID
    mapping(address => uint256) public walletToPatientId;

    /// @notice Mapping from username to patient ID (for friendly lookups)
    mapping(string => uint256) public usernameToPatientId;

    /**
     * @dev See {IERC165-supportsInterface}.
     */
    function supportsInterface(bytes4 interfaceId) public view virtual override(ERC721URIStorage, AccessControl) returns (bool) {
        return ERC721URIStorage.supportsInterface(interfaceId) || AccessControl.supportsInterface(interfaceId);
    }

    /**
     * @dev Struct representing a medical record.
     * @notice Contains metadata about a medical document stored on IPFS.
     */
    struct MedicalRecord {
        uint256 tokenId;
        string ipfsHash;
        string fileName;
        string recordDate;
        string hospital;
        bool isEmergencyViewable;
    }

    /**
     * @dev Struct containing patient profile information.
     */
    struct PatientDetails {
        uint256 patientId;
        string username;
        string name;
        address walletAddress;
        string email;
        uint8 age;
        string bloodGroup;
        MedicalRecord[] medicalRecords;
    }

    /// @notice Mapping from patient ID to PatientDetails
    mapping(uint256 => PatientDetails) public patients;

    /// @dev Counter for assigning unique patient IDs
    uint256 private patientIdCounter;

    /**
     * @dev Struct representing an emergency nominee.
     * @notice Used for emergency contact purposes.
     */
    struct Nominee {
        string name;
        address walletAddress;
        string relationship;
        string contactNumber;
    }

    /// @notice Mapping from patient ID to list of nominees
    mapping(uint256 => Nominee[]) public patientNominees;

    /// @notice Mapping from patient ID to emergency access hash (for magic link verification)
    mapping(uint256 => bytes32) public emergencyAccessHashes;

    /**
     * @dev Struct for logging emergency access events.
     */
    struct AccessLog {
        address accessor;
        string reason;
        uint256 timestamp;
    }

    /// @notice Mapping from patient ID to emergency access logs
    mapping(uint256 => AccessLog[]) public emergencyAccessLogs;

    // Events

    /// @notice Emitted when a patient registers
    /// @param patientId The patient's unique ID
    /// @param wallet The patient's wallet address
    /// @param name The patient's name
    event PatientRegistered(uint256 indexed patientId, address indexed wallet, string name);

    /// @notice Emitted when a medical record is added
    /// @param patientId The patient's unique ID
    /// @param tokenId The NFT token ID
    /// @param ipfsHash The IPFS hash
    event RecordAdded(uint256 indexed patientId, uint256 indexed tokenId, string ipfsHash);

    /// @notice Emitted when emergency access is logged for audit purposes
    /// @param patientId The patient's unique ID
    /// @param accessor The address that accessed the records
    /// @param reason Reason for emergency access
    /// @param timestamp Time of access
    event EmergencyAccessLogged(uint256 indexed patientId, address indexed accessor, string reason, uint256 timestamp);

    /**
     * @dev Checks if a wallet address belongs to a registered patient.
     * @param walletAddress The address to check.
     * @return True if the address belongs to a registered patient.
     */
    function userExists(address walletAddress) public view returns (bool) {
        return walletToPatientId[walletAddress] != 0;
    }

    /**
     * @dev Sets the emergency access hash for the calling patient.
     * @param _hash Hash generated for emergency magic link verification.
     * @notice Caller must be a registered patient.
     */
    function setEmergencyAccessHash(bytes32 _hash) public {
        uint256 patientId = walletToPatientId[msg.sender];
        require(patientId != 0, "Patient not registered");
        emergencyAccessHashes[patientId] = _hash;
    }

    /**
     * @dev Verifies if a given hash matches the patient's emergency access hash.
     * @param _patientId The patient's unique ID.
     * @param _hash The hash to verify.
     * @return True if the hash matches.
     */
    function verifyEmergencyHash(uint256 _patientId, bytes32 _hash) public view returns (bool) {
        return emergencyAccessHashes[_patientId] == _hash;
    }

    /**
     * @dev Step 1: Logs an emergency "Break-Glass" access event for audit trail.
     * @param _patientId The patient's unique ID.
     * @param _reason Reason for the emergency access.
     * @notice Creates an immutable log of who accessed what and why.
     */
    function logEmergencyAccess(uint256 _patientId, string memory _reason) public {
        emergencyAccessLogs[_patientId].push(AccessLog({
            accessor: msg.sender,
            reason: _reason,
            timestamp: block.timestamp
        }));
        emit EmergencyAccessLogged(_patientId, msg.sender, _reason, block.timestamp);
    }

    /**
     * @dev Step 2: Retrieves the audit trail (access logs) for a patient.
     * @param _patientId The patient's unique ID.
     * @return Array of AccessLog structs.
     * @notice Used for compliance and audit purposes.
     */
    function getAccessLogs(uint256 _patientId) public view returns (AccessLog[] memory) {
        return emergencyAccessLogs[_patientId];
    }

    /**
     * @dev Constructor that initializes the ERC721 token with name and symbol.
     */
    constructor() ERC721("MediSecure Record", "MEDREC") {
        _grantRole(DEFAULT_ADMIN_ROLE, msg.sender);
        _grantRole(ADMIN_ROLE, msg.sender);
    }

    modifier onlyRegisteredPatient() {
        require(walletToPatientId[msg.sender] != 0, "Patient not registered");
        _;
    }

    function pauseContract() public onlyRole(ADMIN_ROLE) {
        _pause();
    }

    function unpauseContract() public onlyRole(ADMIN_ROLE) {
        _unpause();
    }

    function grantInsuranceRole(address _insurance) public onlyRole(ADMIN_ROLE) {
        grantRole(INSURANCE_ROLE, _insurance);
    }

    function revokeInsuranceRole(address _insurance) public onlyRole(ADMIN_ROLE) {
        revokeRole(INSURANCE_ROLE, _insurance);
    }

    /**
     * @dev Registers a new patient in the system.
     * @param _username Unique username for the patient.
     * @param _name Patient's full name.
     * @param _email Patient's email address.
     * @param _age Patient's age.
     * @param _bloodGroup Patient's blood group.
     * @notice Caller must not already be registered. Username must be unique.
     */
    function registerPatient(
        string memory _username,
        string memory _name,
        string memory _email,
        uint8 _age,
        string memory _bloodGroup
    ) public whenNotPaused {
        require(
            walletToPatientId[msg.sender] == 0,
            "Patient already registered"
        );
        require(usernameToPatientId[_username] == 0, "Username already taken");
        require(bytes(_username).length >= 3 && bytes(_username).length <= 30, "Username length invalid");
        require(bytes(_name).length > 0 && bytes(_name).length <= 100, "Name length invalid");
        require(bytes(_email).length > 0 && bytes(_email).length <= 100, "Email length invalid");
        require(_age > 0 && _age <= 150, "Age invalid");
        require(bytes(_bloodGroup).length > 0, "Blood group required");

        patientIdCounter++;
        walletToPatientId[msg.sender] = patientIdCounter;
        usernameToPatientId[_username] = patientIdCounter;

        PatientDetails storage newPatient = patients[patientIdCounter];
        newPatient.patientId = patientIdCounter;
        newPatient.username = _username;
        newPatient.name = _name;
        newPatient.walletAddress = msg.sender;
        newPatient.email = _email;
        newPatient.age = _age;
        newPatient.bloodGroup = _bloodGroup;
    }

    /**
     * @dev Updates patient profile details.
     * @param _name Patient's new full name.
     * @param _email Patient's new email address.
     * @param _age Patient's new age.
     * @param _bloodGroup Patient's new blood group.
     * @notice Caller must be a registered patient.
     */
    function updatePatientDetails(
        string memory _name,
        string memory _email,
        uint8 _age,
        string memory _bloodGroup
    ) public whenNotPaused nonReentrant {
        uint256 patientId = walletToPatientId[msg.sender];
        require(patientId != 0, "Patient not registered");
        require(bytes(_name).length > 0 && bytes(_name).length <= 100, "Name length invalid");
        require(bytes(_email).length > 0 && bytes(_email).length <= 100, "Email length invalid");
        require(_age > 0 && _age <= 150, "Age invalid");
        require(bytes(_bloodGroup).length > 0, "Blood group required");

        PatientDetails storage patient = patients[patientId];
        patient.name = _name;
        patient.email = _email;
        patient.age = _age;
        patient.bloodGroup = _bloodGroup;
    }

    /**
     * @dev Adds a nominee (emergency contact) for the patient.
     * @param _name Nominee's full name.
     * @param _walletAddress Nominee's wallet address.
     * @param _relationship Relationship to the patient (e.g., "spouse", "parent").
     * @param _contactNumber Nominee's contact number.
     * @notice Caller must be a registered patient. Multiple nominees allowed.
     */
    function addNominee(
        string memory _name,
        address _walletAddress,
        string memory _relationship,
        string memory _contactNumber
    ) public whenNotPaused nonReentrant {
        uint256 patientId = walletToPatientId[msg.sender];
        require(patientId != 0, "Patient not registered");
        require(bytes(_name).length > 0 && bytes(_name).length <= 100, "Name length invalid");
        require(_walletAddress != address(0), "Invalid wallet address");
        require(bytes(_relationship).length > 0 && bytes(_relationship).length <= 50, "Relationship invalid");

        patientNominees[patientId].push(
            Nominee({
                name: _name,
                walletAddress: _walletAddress,
                relationship: _relationship,
                contactNumber: _contactNumber
            })
        );
    }

    /**
     * @dev Retrieves the list of nominees for a patient.
     * @param _patientId The patient's unique ID.
     * @return Array of Nominee structs.
     */
    function getNominees(
        uint256 _patientId
    ) public view returns (Nominee[] memory) {
        return patientNominees[_patientId];
    }

    /**
     * @dev Adds a medical record for the patient and mints an NFT.
     * @param _ipfsHash IPFS hash of the medical document.
     * @param _fileName Name of the file.
     * @param _recordDate Date of the medical record.
     * @param _hospital Hospital or clinic name.
     * @param _isEmergencyViewable Whether this record can be accessed in emergencies.
     * @notice Mints an ERC721 NFT representing the medical record. Caller must be registered.
     */
    function addMedicalRecord(
        string memory _ipfsHash,
        string memory _fileName,
        string memory _recordDate,
        string memory _hospital,
        bool _isEmergencyViewable
    ) public whenNotPaused nonReentrant {
        uint256 patientId = walletToPatientId[msg.sender];
        require(patientId != 0, "Patient not registered");

        require(bytes(_ipfsHash).length > 0, "IPFS hash required");
        require(bytes(_fileName).length > 0 && bytes(_fileName).length <= 255, "File name invalid");
        require(bytes(_recordDate).length > 0, "Record date required");
        require(bytes(_hospital).length > 0 && bytes(_hospital).length <= 255, "Hospital name invalid");

        // Mint NFT
        uint256 tokenId = _nextTokenId++;
        _mint(msg.sender, tokenId);
        _setTokenURI(tokenId, _ipfsHash);

        patients[patientId].medicalRecords.push(
            MedicalRecord({
                tokenId: tokenId,
                ipfsHash: _ipfsHash,
                fileName: _fileName,
                recordDate: _recordDate,
                hospital: _hospital,
                isEmergencyViewable: _isEmergencyViewable
            })
        );
    }

    /**
     * @dev Toggles the emergency visibility of a specific medical record.
     * @param _recordIndex Index of the medical record in the patient's array.
     * @notice Caller must be a registered patient. Toggles between viewable/non-viewable.
     */
    function toggleEmergencyVisibility(uint256 _recordIndex) public {
        uint256 patientId = walletToPatientId[msg.sender];
        require(patientId != 0, "Patient not registered");
        require(_recordIndex < patients[patientId].medicalRecords.length, "Invalid record index");

        patients[patientId].medicalRecords[_recordIndex].isEmergencyViewable = !patients[patientId].medicalRecords[_recordIndex].isEmergencyViewable;
    }

    /**
     * @dev Retrieves detailed information for a specific patient.
     * @param _patientId The patient's unique ID.
     * @return PatientDetails struct containing all patient information.
     * @notice Validates patient ID is within valid range.
     */
    function getPatientDetails(
        uint256 _patientId
    ) public view returns (PatientDetails memory) {
        require(
            _patientId > 0 && _patientId <= patientIdCounter,
            "Invalid patient ID"
        );
        return patients[_patientId];
    }

    /**
     * @dev Retrieves patient ID from username.
     * @param _username The username to look up.
     * @return Patient ID or 0 if not found.
     * @notice Useful for frontend lookups.
     */
    function getPatientIdByUsername(
        string memory _username
    ) public view returns (uint256) {
        return usernameToPatientId[_username];
    }

    /**
     * @dev Retrieves all medical records for a patient.
     * @param _patientId The patient's unique ID.
     * @return Array of MedicalRecord structs.
     * @notice Validates patient ID is within valid range.
     */
    function getMedicalRecords(
        uint256 _patientId
    ) public view returns (MedicalRecord[] memory) {
        require(
            _patientId > 0 && _patientId <= patientIdCounter,
            "Invalid patient ID"
        );
        return patients[_patientId].medicalRecords;
    }

    function getPatientSummary(uint256 _patientId) public view returns (
        uint256 patientId,
        string memory name,
        string memory email,
        uint8 age,
        string memory bloodGroup,
        uint256 recordCount,
        uint256 nomineeCount,
        bool hasEmergencyHash
    ) {
        require(_patientId > 0 && _patientId <= patientIdCounter, "Invalid patient ID");
        PatientDetails memory p = patients[_patientId];
        return (
            p.patientId,
            p.name,
            p.email,
            p.age,
            p.bloodGroup,
            p.medicalRecords.length,
            patientNominees[_patientId].length,
            emergencyAccessHashes[_patientId] != bytes32(0)
        );
    }

    function getPatientDashboard(address _wallet) public view returns (
        uint256 patientId,
        string memory name,
        uint256 recordCount,
        uint256 nomineeCount,
        bool isRegistered,
        string memory status
    ) {
        patientId = walletToPatientId[_wallet];
        if (patientId == 0) {
            return (0, "", 0, 0, false, "NOT_REGISTERED");
        }
        PatientDetails memory p = patients[patientId];
        return (
            patientId,
            p.name,
            p.medicalRecords.length,
            patientNominees[patientId].length,
            true,
            "ACTIVE"
        );
    }

    function getMedicalRecordsPaginated(
        uint256 _patientId,
        uint256 _offset,
        uint256 _limit
    ) public view returns (MedicalRecord[] memory) {
        require(_patientId > 0 && _patientId <= patientIdCounter, "Invalid patient ID");
        MedicalRecord[] storage allRecords = patients[_patientId].medicalRecords;
        uint256 length = allRecords.length;
        if (_offset >= length) return new MedicalRecord[](0);

        uint256 size = _offset + _limit > length ? length - _offset : _limit;
        MedicalRecord[] memory result = new MedicalRecord[](size);
        for (uint256 i = 0; i < size; i++) {
            result[i] = allRecords[_offset + i];
        }
        return result;
    }

    function getEmergencyLogs(uint256 _patientId) public view returns (AccessLog[] memory) {
        require(_patientId > 0 && _patientId <= patientIdCounter, "Invalid patient ID");
        return emergencyAccessLogs[_patientId];
    }

    function getEmergencyAccessDetails(uint256 _patientId) public view returns (
        bool hasHash,
        bytes32 hash,
        uint256 logCount,
        string memory lastAccessReason,
        uint256 lastAccessTime
    ) {
        require(_patientId > 0 && _patientId <= patientIdCounter, "Invalid patient ID");
        hash = emergencyAccessHashes[_patientId];
        AccessLog[] storage logs = emergencyAccessLogs[_patientId];
        uint256 count = logs.length;

        if (count > 0) {
            AccessLog memory last = logs[count - 1];
            lastAccessReason = last.reason;
            lastAccessTime = last.timestamp;
        }

        return (hash != bytes32(0), hash, count, lastAccessReason, lastAccessTime);
    }

    function getRecentRecords(uint256 _patientId, uint256 _count) public view returns (MedicalRecord[] memory) {
        return getMedicalRecordsPaginated(_patientId, 0, _count);
    }

    function getRecordByIndex(uint256 _patientId, uint256 _index) public view returns (MedicalRecord memory) {
        require(_patientId > 0 && _patientId <= patientIdCounter, "Invalid patient ID");
        require(_index < patients[_patientId].medicalRecords.length, "Index out of bounds");
        return patients[_patientId].medicalRecords[_index];
    }

    function addMedicalRecordsBatch(
        string[] memory _ipfsHashes,
        string[] memory _fileNames,
        string[] memory _recordDates,
        string[] memory _hospitals,
        bool[] memory _emergencyViewable
    ) public {
        require(_ipfsHashes.length == _fileNames.length, "Length mismatch");
        require(_ipfsHashes.length == _recordDates.length, "Length mismatch");
        require(_ipfsHashes.length == _hospitals.length, "Length mismatch");
        require(_ipfsHashes.length == _emergencyViewable.length, "Length mismatch");

        uint256 patientId = walletToPatientId[msg.sender];
        require(patientId != 0, "Patient not registered");

        for (uint256 i = 0; i < _ipfsHashes.length; i++) {
            uint256 tokenId = _nextTokenId++;
            _mint(msg.sender, tokenId);
            _setTokenURI(tokenId, _ipfsHashes[i]);

            patients[patientId].medicalRecords.push(
                MedicalRecord({
                    tokenId: tokenId,
                    ipfsHash: _ipfsHashes[i],
                    fileName: _fileNames[i],
                    recordDate: _recordDates[i],
                    hospital: _hospitals[i],
                    isEmergencyViewable: _emergencyViewable[i]
                })
            );
        }
    }

    }

